insert into public.projects (id, title, slug, short_description, long_description, problem, solution, target_user, category, status, tags, stack, features, product_decisions, technical_challenges, learnings, potential, demo_url, github_url, video_url, cover_image_url, og_image_url, seo_title, seo_description, is_published, is_featured, featured_order, highlight_level) values ('funded-os', 'FundedOS · Gestión para traders de fondeo', 'funded-os-traders-fondeo', 'Dashboard para centralizar cuentas de fondeo, métricas, riesgo, retiros y análisis post-trade.', 'Aplicativo web para traders que operan cuentas de fondeo y necesitan visualizar su desempeño global, controlar reglas, registrar trades y tomar mejores decisiones sobre riesgo y reinversión.', 'Los traders de fondeo suelen manejar cuentas, reglas, retiros, métricas y estados en herramientas dispersas. Esto dificulta ver el riesgo real y la evolución del negocio de trading.', 'Un sistema centralizado con dashboard, gestión de cuentas, calendario de resultados, registro manual de trades, debriefing asistido por IA, playbook de reglas, reportes y planeación de retiros/reinversión.', 'Traders intradía que operan cuentas de fondeo en futuros, especialmente Nasdaq y otros activos líquidos.', 'SaaS / Trading Dashboard', 'MVP', array['Trading', 'Dashboard', 'SaaS', 'IA', 'Finanzas']::text[], array['Next.js', 'TypeScript', 'Supabase', 'Vercel', 'Tailwind CSS', 'AI-assisted flows']::text[], array['Dashboard global de cuentas', 'PYG diario, semanal, mensual y acumulado', 'Win rate global', 'Calendario de resultados', 'Registro manual de trades', 'Debriefing post-trade con IA', 'Playbook de reglas', 'Planeación de retiros y reinversión']::text[], array['Priorizar métricas accionables sobre visualizaciones decorativas.', 'Separar cuentas, trades y reportes para permitir análisis por activo y periodo.', 'Usar IA como apoyo de reflexión post-trade, no como sistema de señales.']::text[], array['Modelar datos de cuentas, trades, activos y reportes sin perder claridad.', 'Diseñar una experiencia útil para desktop y móvil.', 'Preparar el sistema para alertas y reglas por cuenta.']::text[], array['Un producto financiero necesita claridad antes que complejidad.', 'Las métricas deben responder preguntas operativas concretas.', 'El trading puede convertirse en un sistema de gestión, no solo en operaciones aisladas.']::text[], array['SaaS vertical', 'Contenido para traders', 'Caso de estudio técnico', 'Servicio de dashboard especializado']::text[], null, null, null, '/projects/funded-os.svg', null, 'FundedOS · Dashboard para traders de cuentas de fondeo', 'Proyecto de dashboard para traders de fondeo con métricas, riesgo, retiros, cuentas, trades y debriefing post-trade con IA.', true, true, 1, 'principal') on conflict (id) do update set title=excluded.title, slug=excluded.slug, short_description=excluded.short_description, long_description=excluded.long_description, problem=excluded.problem, solution=excluded.solution, target_user=excluded.target_user, category=excluded.category, status=excluded.status, tags=excluded.tags, stack=excluded.stack, features=excluded.features, product_decisions=excluded.product_decisions, technical_challenges=excluded.technical_challenges, learnings=excluded.learnings, potential=excluded.potential, demo_url=excluded.demo_url, github_url=excluded.github_url, video_url=excluded.video_url, cover_image_url=excluded.cover_image_url, og_image_url=excluded.og_image_url, seo_title=excluded.seo_title, seo_description=excluded.seo_description, is_published=excluded.is_published, is_featured=excluded.is_featured, featured_order=excluded.featured_order, highlight_level=excluded.highlight_level, updated_at=now();
insert into public.projects (id, title, slug, short_description, long_description, problem, solution, target_user, category, status, tags, stack, features, product_decisions, technical_challenges, learnings, potential, demo_url, github_url, video_url, cover_image_url, og_image_url, seo_title, seo_description, is_published, is_featured, featured_order, highlight_level) values ('hogar-cfo', 'Hogar CFO · Finanzas domésticas medibles', 'hogar-cfo-finanzas-domesticas', 'PWA para gestionar gastos, mercado, presupuestos, históricos de precios y proyectos financieros del hogar.', 'Sistema tipo CFO doméstico para convertir las finanzas del hogar en un proceso más claro, medible y planificado.', 'Las familias suelen tomar decisiones financieras con datos dispersos: recibos, mercado, presupuestos, deudas, gastos y proyectos sin una vista centralizada.', 'Una PWA con registros, presupuestos, histórico de precios, comparativos, métricas y planificación de proyectos grandes del hogar.', 'Hogares, parejas o familias que quieren controlar mejor mercado, gastos, presupuestos y decisiones financieras.', 'PWA / Finance Dashboard', 'MVP', array['Finanzas', 'PWA', 'Dashboard', 'Hogar', 'Supabase']::text[], array['Next.js', 'TypeScript', 'Supabase', 'Vercel', 'Tailwind CSS']::text[], array['Registro de compras y gastos', 'Presupuestos mensuales', 'Histórico de precios por producto', 'Comparativos de mercado', 'Métricas del hogar', 'Planeación de proyectos financieros', 'Acceso por usuario']::text[], array['Pensar el hogar como una unidad financiera con métricas propias.', 'Diseñar el registro de mercado como fuente de datos, no solo como lista.', 'Separar gastos cotidianos de decisiones financieras grandes.']::text[], array['Evitar cálculos inconsistentes por fechas o periodos.', 'Diseñar flujos simples para usuarios no técnicos.', 'Crear estructuras reutilizables para presupuestos y categorías.']::text[], array['La gestión doméstica puede beneficiarse de conceptos de análisis financiero.', 'El histórico de precios convierte compras rutinarias en información estratégica.', 'Un buen dashboard debe reducir ansiedad, no aumentarla.']::text[], array['Freelance', 'SaaS familiar', 'Contenido financiero', 'Caso de estudio de producto']::text[], null, null, null, '/projects/hogar-cfo.svg', null, 'Hogar CFO · PWA para finanzas domésticas', 'Proyecto PWA para gestionar gastos del hogar, mercado, presupuestos, histórico de precios y decisiones financieras familiares.', true, true, 2, 'principal') on conflict (id) do update set title=excluded.title, slug=excluded.slug, short_description=excluded.short_description, long_description=excluded.long_description, problem=excluded.problem, solution=excluded.solution, target_user=excluded.target_user, category=excluded.category, status=excluded.status, tags=excluded.tags, stack=excluded.stack, features=excluded.features, product_decisions=excluded.product_decisions, technical_challenges=excluded.technical_challenges, learnings=excluded.learnings, potential=excluded.potential, demo_url=excluded.demo_url, github_url=excluded.github_url, video_url=excluded.video_url, cover_image_url=excluded.cover_image_url, og_image_url=excluded.og_image_url, seo_title=excluded.seo_title, seo_description=excluded.seo_description, is_published=excluded.is_published, is_featured=excluded.is_featured, featured_order=excluded.featured_order, highlight_level=excluded.highlight_level, updated_at=now();
insert into public.projects (id, title, slug, short_description, long_description, problem, solution, target_user, category, status, tags, stack, features, product_decisions, technical_challenges, learnings, potential, demo_url, github_url, video_url, cover_image_url, og_image_url, seo_title, seo_description, is_published, is_featured, featured_order, highlight_level) values ('wat-latam', 'W&T Hub Latam · Comunidad Work and Travel', 'work-and-travel-hub-latam', 'Plataforma comunitaria para latinos que hacen Work and Travel USA, con destinos, planes, grupos, hacks y pauta.', 'Web comunitaria enfocada en resolver necesidades de información, conexión y descubrimiento para participantes latinos de Work and Travel USA.', 'La información sobre destinos, grupos, agencias, planes y hacks de Work and Travel está fragmentada en chats, redes y recomendaciones informales.', 'Una plataforma con reseñas de destinos, planes por ciudad, grupos de WhatsApp, hacks, parches, perfiles, admin de moderación y espacios de pauta para agencias.', 'Participantes o aspirantes de Work and Travel USA de Colombia, Ecuador y México.', 'Community Platform', 'En validación', array['Comunidad', 'Marketplace', 'SEO', 'Work and Travel', 'UGC']::text[], array['Next.js', 'TypeScript', 'Supabase', 'Vercel', 'Tailwind CSS']::text[], array['Destinos con reseñas', 'Planes por zona', 'Grupos de WhatsApp', 'Hacks de usuarios', 'Parches post-trabajo', 'Perfil de usuario', 'Panel admin de aprobación', 'Sección de pauta/agencias']::text[], array['Diseñar la plataforma alrededor de contenido generado por usuarios.', 'Incluir moderación para mantener calidad y seguridad.', 'Separar comunidad y monetización desde la arquitectura inicial.']::text[], array['Gestionar contenido público creado por usuarios.', 'Estructurar permisos entre usuarios y administrador.', 'Pensar en SEO para destinos y necesidades específicas.']::text[], array['Una comunidad necesita flujos de confianza y moderación.', 'El contenido útil puede convertirse en adquisición orgánica.', 'Los nichos con dolor informativo tienen potencial de plataforma.']::text[], array['SEO', 'Comunidad', 'Pauta', 'Caso de estudio full-stack']::text[], null, null, null, '/projects/wat-hub.svg', null, 'W&T Hub Latam · Plataforma Work and Travel para latinos', 'Proyecto de plataforma comunitaria para Work and Travel USA con reseñas, grupos, hacks, planes y oportunidades para latinos.', true, true, 3, 'principal') on conflict (id) do update set title=excluded.title, slug=excluded.slug, short_description=excluded.short_description, long_description=excluded.long_description, problem=excluded.problem, solution=excluded.solution, target_user=excluded.target_user, category=excluded.category, status=excluded.status, tags=excluded.tags, stack=excluded.stack, features=excluded.features, product_decisions=excluded.product_decisions, technical_challenges=excluded.technical_challenges, learnings=excluded.learnings, potential=excluded.potential, demo_url=excluded.demo_url, github_url=excluded.github_url, video_url=excluded.video_url, cover_image_url=excluded.cover_image_url, og_image_url=excluded.og_image_url, seo_title=excluded.seo_title, seo_description=excluded.seo_description, is_published=excluded.is_published, is_featured=excluded.is_featured, featured_order=excluded.featured_order, highlight_level=excluded.highlight_level, updated_at=now();
insert into public.projects (id, title, slug, short_description, long_description, problem, solution, target_user, category, status, tags, stack, features, product_decisions, technical_challenges, learnings, potential, demo_url, github_url, video_url, cover_image_url, og_image_url, seo_title, seo_description, is_published, is_featured, featured_order, highlight_level) values ('personal-crm', 'Personal CRM · Relaciones gestionadas con intención', 'personal-crm-relaciones', 'PWA para registrar relaciones, fechas importantes, interacciones y oportunidades de conexión.', 'Herramienta personal para gestionar relaciones importantes con seguimiento, recordatorios y oportunidades de generar valor.', 'Las relaciones importantes suelen depender de memoria, chats dispersos o recordatorios informales. Eso hace que se olviden fechas, compromisos y oportunidades.', 'Un CRM personal con contactos, fechas, acciones, interacciones, oportunidades y sugerencias para conectar personas.', 'Personas que quieren cultivar relaciones personales, networking o vínculos profesionales de forma intencional.', 'PWA / Personal Productivity', 'MVP', array['Productividad', 'CRM', 'PWA', 'Relaciones', 'IA']::text[], array['Next.js', 'Supabase', 'Vercel', 'Tailwind CSS']::text[], array['Contactos y relaciones', 'Fechas importantes', 'Acciones prioritarias', 'Interacciones recientes', 'Oportunidades de conexión', 'Dashboard personal']::text[], array['Enfocar el producto en acciones y oportunidades, no solo en contactos.', 'Diseñar para uso móvil frecuente.', 'Preparar la lógica para sugerencias asistidas por IA.']::text[], array['Crear una experiencia simple para registrar información sensible.', 'Organizar datos personales sin hacer la app pesada.', 'Priorizar acciones útiles en el dashboard.']::text[], array['La productividad personal también puede diseñarse como sistema.', 'Un buen producto de relaciones debe sentirse humano y no mecánico.', 'Las sugerencias deben ser discretas y contextuales.']::text[], array['Productividad personal', 'SaaS ligero', 'Caso de estudio móvil']::text[], null, null, null, '/projects/personal-crm.svg', null, 'Personal CRM · PWA para gestionar relaciones personales', 'Proyecto de PWA para gestionar relaciones personales, fechas importantes, interacciones y oportunidades de conexión.', true, false, 4, 'secundario') on conflict (id) do update set title=excluded.title, slug=excluded.slug, short_description=excluded.short_description, long_description=excluded.long_description, problem=excluded.problem, solution=excluded.solution, target_user=excluded.target_user, category=excluded.category, status=excluded.status, tags=excluded.tags, stack=excluded.stack, features=excluded.features, product_decisions=excluded.product_decisions, technical_challenges=excluded.technical_challenges, learnings=excluded.learnings, potential=excluded.potential, demo_url=excluded.demo_url, github_url=excluded.github_url, video_url=excluded.video_url, cover_image_url=excluded.cover_image_url, og_image_url=excluded.og_image_url, seo_title=excluded.seo_title, seo_description=excluded.seo_description, is_published=excluded.is_published, is_featured=excluded.is_featured, featured_order=excluded.featured_order, highlight_level=excluded.highlight_level, updated_at=now();
insert into public.projects (id, title, slug, short_description, long_description, problem, solution, target_user, category, status, tags, stack, features, product_decisions, technical_challenges, learnings, potential, demo_url, github_url, video_url, cover_image_url, og_image_url, seo_title, seo_description, is_published, is_featured, featured_order, highlight_level) values ('futures-risk-calculator', 'Futures Risk Voice Calculator', 'futures-risk-voice-calculator', 'Extensión Chrome para calcular contratos de futuros con entrada por voz y respuesta auditiva.', 'Microherramienta para traders que necesitan calcular contratos de forma rápida durante la operativa, usando texto o dictado por voz.', 'Durante una sesión de trading, calcular contratos manualmente puede generar fricción, errores o pérdida de tiempo.', 'Una extensión Chrome que recibe datos escritos o dictados, calcula contratos y entrega respuesta escrita y auditiva.', 'Traders intradía de futuros, especialmente operadores de microcontratos.', 'Chrome Extension', 'Prototipo', array['Chrome Extension', 'Trading', 'Voz', 'Productividad']::text[], array['JavaScript', 'Chrome Extensions', 'Web Speech API', 'HTML', 'CSS']::text[], array['Entrada por voz', 'Cálculo de contratos', 'Respuesta escrita', 'Respuesta por audio', 'Flujo rápido de uso']::text[], array['Reducir la cantidad de clics necesarios durante una operación.', 'Usar voz como forma de entrada rápida.', 'Priorizar claridad numérica sobre diseño complejo.']::text[], array['Manejar dictado con palabras variables.', 'Estandarizar cálculos por contrato.', 'Crear una experiencia usable desde extensión.']::text[], array['Las mejores microherramientas resuelven un problema muy específico.', 'La voz puede reducir fricción en contextos de alta atención.', 'Una extensión puede ser un buen MVP antes de construir un SaaS.']::text[], array['Micro-SaaS', 'Demo técnica', 'Contenido para traders']::text[], null, null, null, '/projects/futures-calculator.svg', null, 'Futures Risk Voice Calculator · Extensión Chrome para traders', 'Extensión Chrome para calcular contratos de futuros con entrada por voz y respuesta auditiva.', true, false, 5, 'experimento') on conflict (id) do update set title=excluded.title, slug=excluded.slug, short_description=excluded.short_description, long_description=excluded.long_description, problem=excluded.problem, solution=excluded.solution, target_user=excluded.target_user, category=excluded.category, status=excluded.status, tags=excluded.tags, stack=excluded.stack, features=excluded.features, product_decisions=excluded.product_decisions, technical_challenges=excluded.technical_challenges, learnings=excluded.learnings, potential=excluded.potential, demo_url=excluded.demo_url, github_url=excluded.github_url, video_url=excluded.video_url, cover_image_url=excluded.cover_image_url, og_image_url=excluded.og_image_url, seo_title=excluded.seo_title, seo_description=excluded.seo_description, is_published=excluded.is_published, is_featured=excluded.is_featured, featured_order=excluded.featured_order, highlight_level=excluded.highlight_level, updated_at=now();
insert into public.projects (id, title, slug, short_description, long_description, problem, solution, target_user, category, status, tags, stack, features, product_decisions, technical_challenges, learnings, potential, demo_url, github_url, video_url, cover_image_url, og_image_url, seo_title, seo_description, is_published, is_featured, featured_order, highlight_level) values ('daily-thinker-ai', 'Daily Thinker AI · Reflexión contextual', 'daily-thinker-ai-reflexion-contextual', 'Extensión Chrome que adapta enseñanzas de pensadores al contexto, profesión o mood del usuario.', 'Experimento de IA y productividad personal que convierte citas o ideas de pensadores en reflexiones accionables para la vida cotidiana.', 'Las frases motivacionales suelen ser genéricas y no conectan con el contexto real del usuario.', 'Una extensión que toma profesión, mood o contexto y adapta una enseñanza relevante a la situación del usuario.', 'Personas interesadas en aprendizaje, reflexión, productividad y desarrollo personal con IA.', 'Chrome Extension / AI', 'Idea', array['IA', 'Chrome Extension', 'Productividad', 'Prompt Engineering']::text[], array['JavaScript', 'Chrome Extensions', 'LLMs', 'Prompt Engineering']::text[], array['Citas de pensadores', 'Contexto del usuario', 'Adaptación con IA', 'Reflexión accionable', 'Experiencia ligera']::text[], array['Evitar contenido motivacional genérico.', 'Usar IA para contextualizar, no para producir texto vacío.', 'Mantener una experiencia rápida tipo extensión.']::text[], array['Crear prompts consistentes.', 'Evitar respuestas repetitivas o exageradas.', 'Diseñar una UI mínima pero útil.']::text[], array['La personalización es el valor diferencial en contenido asistido por IA.', 'Un microproducto puede probar una hipótesis de comportamiento.', 'La utilidad importa más que la cantidad de texto generado.']::text[], array['Experimento de IA', 'Contenido', 'Productividad personal']::text[], null, null, null, '/projects/daily-thinker.svg', null, 'Daily Thinker AI · Extensión de reflexión personalizada con IA', 'Extensión Chrome experimental que adapta enseñanzas de pensadores al contexto y mood del usuario con IA.', true, false, 6, 'experimento') on conflict (id) do update set title=excluded.title, slug=excluded.slug, short_description=excluded.short_description, long_description=excluded.long_description, problem=excluded.problem, solution=excluded.solution, target_user=excluded.target_user, category=excluded.category, status=excluded.status, tags=excluded.tags, stack=excluded.stack, features=excluded.features, product_decisions=excluded.product_decisions, technical_challenges=excluded.technical_challenges, learnings=excluded.learnings, potential=excluded.potential, demo_url=excluded.demo_url, github_url=excluded.github_url, video_url=excluded.video_url, cover_image_url=excluded.cover_image_url, og_image_url=excluded.og_image_url, seo_title=excluded.seo_title, seo_description=excluded.seo_description, is_published=excluded.is_published, is_featured=excluded.is_featured, featured_order=excluded.featured_order, highlight_level=excluded.highlight_level, updated_at=now();
insert into public.services (id, title, slug, short_description, ideal_client, problem, deliverables, scope, exclusions, price_from, price_note, cta_text, is_active, sort_order) values ('mvp-web', 'MVP web con login y base de datos', 'mvp-web-login-base-datos', 'Primera versión funcional de una idea digital con usuarios, datos y dashboard básico.', 'Emprendedores, traders, profesionales independientes o comunidades que quieren validar una idea.', 'Hay una idea clara, pero todavía no existe una herramienta funcional que pueda probarse con usuarios reales.', array['Arquitectura inicial', 'Flujo principal', 'Login', 'Base de datos', 'Dashboard básico', 'Deploy']::text[], array['MVP acotado', '1 a 3 flujos principales', 'Diseño responsive', 'Documentación de uso']::text[], array['Apps móviles nativas', 'IA avanzada personalizada', 'Integraciones enterprise complejas']::text[], 'Desde 2.5M COP', 'El precio depende de alcance, número de flujos y complejidad de datos.', 'Construir un MVP', true, 1) on conflict (id) do update set title=excluded.title, slug=excluded.slug, short_description=excluded.short_description, ideal_client=excluded.ideal_client, problem=excluded.problem, deliverables=excluded.deliverables, scope=excluded.scope, exclusions=excluded.exclusions, price_from=excluded.price_from, price_note=excluded.price_note, cta_text=excluded.cta_text, is_active=excluded.is_active, sort_order=excluded.sort_order, updated_at=now();
insert into public.services (id, title, slug, short_description, ideal_client, problem, deliverables, scope, exclusions, price_from, price_note, cta_text, is_active, sort_order) values ('dashboard-operativo', 'Dashboard operativo', 'dashboard-operativo', 'Sistema visual para convertir registros dispersos en métricas claras y accionables.', 'Negocios o personas que manejan datos en Excel, Notion, WhatsApp o registros manuales.', 'Los datos existen, pero no hay visibilidad clara para tomar decisiones.', array['Modelo de datos', 'Pantalla de registros', 'Métricas clave', 'Filtros', 'Visualización responsive']::text[], array['Dashboard básico o medio', 'Indicadores priorizados', 'Carga manual de datos', 'Deploy web']::text[], array['BI corporativo avanzado', 'Integraciones masivas', 'Migraciones complejas']::text[], 'Desde 1.2M COP', 'Ideal para una primera versión de control interno.', 'Diseñar un dashboard', true, 2) on conflict (id) do update set title=excluded.title, slug=excluded.slug, short_description=excluded.short_description, ideal_client=excluded.ideal_client, problem=excluded.problem, deliverables=excluded.deliverables, scope=excluded.scope, exclusions=excluded.exclusions, price_from=excluded.price_from, price_note=excluded.price_note, cta_text=excluded.cta_text, is_active=excluded.is_active, sort_order=excluded.sort_order, updated_at=now();
insert into public.services (id, title, slug, short_description, ideal_client, problem, deliverables, scope, exclusions, price_from, price_note, cta_text, is_active, sort_order) values ('landing-estrategica', 'Landing page estratégica', 'landing-page-estrategica', 'Página comercial clara para explicar, vender o validar una oferta.', 'Profesionales, marcas personales, productos en validación o servicios especializados.', 'La oferta existe, pero no está comunicada de forma clara ni orientada a conversión.', array['Estructura comercial', 'Copy base', 'Diseño responsive', 'Formulario/contacto', 'SEO inicial']::text[], array['Landing de 1 página', 'Secciones clave', 'Optimización mobile', 'Deploy']::text[], array['E-commerce completo', 'CMS complejo', 'Branding visual completo']::text[], 'Desde 700k COP', 'Puede escalar si incluye copy avanzado, múltiples páginas o integraciones.', 'Crear una landing', true, 3) on conflict (id) do update set title=excluded.title, slug=excluded.slug, short_description=excluded.short_description, ideal_client=excluded.ideal_client, problem=excluded.problem, deliverables=excluded.deliverables, scope=excluded.scope, exclusions=excluded.exclusions, price_from=excluded.price_from, price_note=excluded.price_note, cta_text=excluded.cta_text, is_active=excluded.is_active, sort_order=excluded.sort_order, updated_at=now();
insert into public.services (id, title, slug, short_description, ideal_client, problem, deliverables, scope, exclusions, price_from, price_note, cta_text, is_active, sort_order) values ('automatizacion-ia', 'Automatización simple con IA', 'automatizacion-simple-ia', 'Flujos asistidos por IA para reducir tareas repetitivas de texto, análisis o clasificación.', 'Profesionales o equipos pequeños que repiten tareas manuales y quieren sistematizarlas.', 'Hay procesos que consumen tiempo y podrían resolverse con formularios, prompts, plantillas o IA aplicada.', array['Diagnóstico de flujo', 'Prompt system', 'Interfaz simple', 'Documentación', 'Prueba de uso']::text[], array['Automatización acotada', 'Un flujo principal', 'Uso de herramientas existentes o integración simple']::text[], array['Modelos entrenados desde cero', 'Agentes autónomos críticos', 'Procesos legales/médicos sin revisión humana']::text[], 'Desde 600k COP', 'El alcance se define por número de pasos y sensibilidad del proceso.', 'Automatizar un flujo', true, 4) on conflict (id) do update set title=excluded.title, slug=excluded.slug, short_description=excluded.short_description, ideal_client=excluded.ideal_client, problem=excluded.problem, deliverables=excluded.deliverables, scope=excluded.scope, exclusions=excluded.exclusions, price_from=excluded.price_from, price_note=excluded.price_note, cta_text=excluded.cta_text, is_active=excluded.is_active, sort_order=excluded.sort_order, updated_at=now();
