insert into public.home_sections (key, title, subtitle, content, cta_label, cta_url, is_active, sort_order) values ('hero', 'Construyo herramientas web e IA para convertir procesos complejos en sistemas accionables.', 'Product builder · Web tools · AI applied systems', 'Diseño y desarrollo productos digitales, dashboards, PWAs y automatizaciones para nichos específicos como trading, finanzas, comunidades y productividad.', 'Ver proyectos', '/proyectos', true, 1) on conflict (key) do update set title=excluded.title, subtitle=excluded.subtitle, content=excluded.content, cta_label=excluded.cta_label, cta_url=excluded.cta_url, is_active=excluded.is_active, sort_order=excluded.sort_order, updated_at=now();
